import { ChangeDetectionStrategy, Component, signal } from '@angular/core';

import { HbSegmentedImports, type HbSegmentedOption } from '@herbst/ui';

@Component({
  selector: 'hb-demo-segmented-basic',
  imports: [HbSegmentedImports],
  template: `
    <div class="flex flex-col items-start gap-2">
      <hb-segmented [hbOptions]="options" [(hbValue)]="view" hbAriaLabel="Catalogue view" />
      <p class="font-mono text-[12px] text-muted-foreground">Selected: {{ view() }}</p>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoSegmentedBasicComponent {
  protected readonly view = signal('all');
  protected readonly options: HbSegmentedOption[] = [
    { value: 'all', label: 'All' },
    { value: 'photos', label: 'Photos' },
    { value: 'videos', label: 'Videos' },
    { value: 'archived', label: 'Archived', disabled: true },
  ];
}

import { ChangeDetectionStrategy, Component, signal } from '@angular/core';

import { HbSegmentedImports } from '@herbst/ui';
import { provideIcons } from '@ng-icons/core';
import { phosphorBell, phosphorLeaf, phosphorTag } from '@ng-icons/phosphor-icons/regular';

@Component({
  selector: 'hb-demo-segmented-icons',
  imports: [HbSegmentedImports],
  viewProviders: [provideIcons({ phosphorLeaf, phosphorTag, phosphorBell })],
  template: `
    <hb-segmented [(hbValue)]="section" hbAriaLabel="Section">
      <hb-segmented-item value="specimens" label="Photos" hbIcon="phosphorLeaf" />
      <hb-segmented-item value="families" label="Forests" hbIcon="phosphorTag" />
      <hb-segmented-item value="alerts" label="Alerts" hbIcon="phosphorBell" hbDisabled />
    </hb-segmented>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoSegmentedIconsComponent {
  protected readonly section = signal('specimens');
}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbSegmentedImports, type HbSegmentedOption } from '@herbst/ui';

@Component({
  selector: 'hb-demo-segmented-sizes',
  imports: [HbSegmentedImports],
  template: `
    <div class="flex w-full max-w-md flex-col gap-4">
      <hb-segmented hbSize="xs" [hbOptions]="options" [hbValue]="'all'" />
      <hb-segmented hbSize="sm" [hbOptions]="options" [hbValue]="'all'" />
      <hb-segmented hbSize="lg" [hbOptions]="options" [hbValue]="'all'" />
      <hb-segmented hbSize="xl" [hbOptions]="options" [hbValue]="'all'" />

      <hb-segmented hbFluid [hbOptions]="options" [hbValue]="'photos'" />
      <hb-segmented hbDisabled [hbOptions]="options" [hbValue]="'videos'" />
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoSegmentedSizesComponent {
  protected readonly options: HbSegmentedOption[] = [
    { value: 'all', label: 'All' },
    { value: 'photos', label: 'Photos' },
    { value: 'videos', label: 'Videos' },
  ];
}
